def gen(rng, size):
    n = rng.randint(1, max(1, size))
    ops = []
    depth = 0
    for _ in range(n):
        choices = ['num']
        if depth >= 1:
            choices += ['D', 'C']
        if depth >= 2:
            choices += ['+']
        c = rng.choice(choices)
        if c == 'num':
            ops.append(str(rng.randint(-30000, 30000)))
            depth += 1
        elif c == 'D':
            ops.append('D')
            depth += 1
        elif c == '+':
            ops.append('+')
            depth += 1
        else:
            ops.append('C')
            depth -= 1
    return [ops]

