class Solution:
    def calPoints(self, operations):
        rec = []
        for op in operations:
            if op == 'C':
                rec.pop()
            elif op == 'D':
                rec.append(2 * rec[-1])
            elif op == '+':
                rec.append(rec[-1] + rec[-2])
            else:
                rec.append(int(op))
        total = 0
        for v in rec:
            total += v
        return total

