var calPoints = function(operations) {
    const st = [];
    for (const op of operations) {
        if (op === 'C') st.pop();
        else if (op === 'D') st.push(2 * st[st.length - 1]);
        else if (op === '+') st.push(st[st.length - 1] + st[st.length - 2]);
        else st.push(parseInt(op, 10));
    }
    return st.reduce((a, b) => a + b, 0);
};
